export interface Skill {
  name: string;
  description: string;
  content: string;
}

// Skill content embedded at build time — loaded from habitat-skills SKILL.md files
export const SKILLS: Skill[] = [
  {
    name: "founder-context",
    description:
      "Set up your project context so all other skills know your idea, audience, and stage. Run this first.",
    content: `When a founder wants to set up their context, help them create a .claude/founder-context.md file with:
- Idea (one sentence)
- Problem they're solving
- Target audience
- Current stage (idea / validated / building / launched)
- What they've built so far
- Key metrics or traction (if any)
- Goals for the next 30 days`,
  },
  {
    name: "idea-validation",
    description:
      "Validate a startup idea using structured frameworks — problem-solution fit, TAM/SAM/SOM, Mom Test interview design, assumption mapping, go/no-go scorecard.",
    content: `Run through 5 validation lenses: (1) Problem Validation — is this a real, frequent, costly problem? (2) Solution Validation — is this a painkiller or vitamin? (3) Market Sizing — TAM/SAM/SOM. (4) Competitive Landscape — what exists, what's the gap? (5) Founder-Market Fit — why are you the right person to build this? Output a go/no-go scorecard with clear next steps.`,
  },
  {
    name: "competitor-research",
    description:
      "Research competitors, find gaps, and identify positioning angles.",
    content: `Map the competitive landscape: identify direct and indirect competitors, compare on key dimensions (price, features, target customer, distribution), find underserved segments or unmet needs, and output a positioning recommendation.`,
  },
  {
    name: "customer-segments",
    description:
      "Generate customer segments with personas, pain points, and outreach strategy per segment.",
    content: `Define 3–5 customer segments. For each: name, demographics/firmographics, core pain point, current solution, willingness to pay, and where to find them. Rank segments by attractiveness for early-stage outreach.`,
  },
  {
    name: "landing-page",
    description:
      "Build a conversion-focused landing page — copy, structure, and code.",
    content: `Create a landing page structure: Hero (headline, subheadline, CTA), Problem section, Solution section, How it works, Social proof, FAQ, Final CTA. Write the copy for each section. Optimize the headline to be outcome-focused, not feature-focused.`,
  },
  {
    name: "prototype-sprint",
    description:
      "Plan and execute a focused prototype sprint — scope, prioritize, build.",
    content: `Help the founder scope a 1–5 day prototype sprint: define the riskiest assumption to test, identify the minimum build to test it, create a day-by-day plan, and define success criteria.`,
  },
  {
    name: "mvp-scope",
    description:
      "Cut your feature list down to a true MVP with a clear build checklist.",
    content: `Apply ruthless prioritization to a feature list. Keep only what is necessary to deliver the core value promise and test the key hypothesis. Output a build checklist with priorities: must-have, nice-to-have, cut.`,
  },
  {
    name: "pitch-deck",
    description:
      "Create pitches — 30-second elevator pitch, demo scripts, objection prep.",
    content: `Build three pitch artifacts: (1) 30-second elevator pitch (problem → solution → traction → ask), (2) 5-minute demo script with key talking points, (3) Objection handling for the 5 most common investor/customer objections.`,
  },
  {
    name: "first-users",
    description:
      "Find your first 10, then 100 users with a targeted outreach playbook.",
    content: `Stage 1 (first 10): manually recruit from personal network, communities, and warm outreach. Stage 2 (first 100): expand to cold outreach, community posts, and referral loops. Output a specific 30-day action plan with daily tasks.`,
  },
  {
    name: "launch-plan",
    description:
      "Create a phased launch strategy — pre-launch, launch day, post-launch.",
    content: `Build a launch plan covering: pre-launch (audience building, content prep, product prep), launch day schedule, and post-launch follow-through (days 1–7, 30-day plan). Include platform-specific playbooks for LinkedIn, Twitter/X, Product Hunt, and Reddit.`,
  },
  {
    name: "social-content",
    description:
      "Create launch posts, build-in-public updates, and social media content.",
    content: `Write social content for: launch announcement post, build-in-public update, milestone celebration, and lesson-learned post. Adapt for LinkedIn (story-driven, professional) and Twitter/X (punchy, conversational).`,
  },
  {
    name: "mom-test",
    description:
      "Run customer discovery conversations using the Mom Test framework — ask about their life, not your idea. Identify real signals vs. polite validation.",
    content: `Apply the Mom Test: (1) Ask about their life, not your idea. (2) Ask about specifics, not hypotheticals. (3) Listen more than you talk. Generate a tailored interview guide with opening script, core questions (context → problem depth → current solutions → priority), closing + referral ask, and a signal interpretation guide (strong signals vs. red flags). Output a decision framework after N interviews.`,
  },
  {
    name: "gtm-strategy",
    description:
      "Build a go-to-market strategy — ICP definition, GTM motion selection, channel prioritization, messaging framework, and 90-day plan.",
    content: `Four steps: (1) ICP worksheet — firmographic/demographic, psychographic, behavioral, deal-breakers. (2) GTM motion selection — PLG, sales-led, community-led, content-led, or outbound. (3) Channel scoring matrix — rate reach × ICP fit × cost × speed, pick top 2. (4) Messaging framework — one-liner, before/after state, proof points, CTA. Output a 30/60/90-day plan with success metrics.`,
  },
  {
    name: "sales-outreach",
    description:
      "Write cold email and LinkedIn outreach sequences tailored to the ICP and product. Includes problem-led, result-led, referral, and feedback-ask templates.",
    content: `Generate ready-to-send outreach: (1) 3 email variants (problem-led, result-led, feedback ask) with 3 subject line A/B options each. (2) LinkedIn connection note + first DM. (3) Personalization hooks to research per prospect. (4) Reply handling guidance pointing to follow-up tracks. Keep all emails under 100 words. One problem, one ask.`,
  },
  {
    name: "follow-up-tracks",
    description:
      "Handle every post-contact scenario — warm leads, ghosted prospects, objections, post-demo closing. Full sequences for each track.",
    content: `Four tracks: (1) Warm Lead — pre-call confirmation, post-demo follow-up (same day), day 3 value add, day 7 nudge. (2) Ghosted — day 3 value add, day 7 check-in, day 14 reframe, day 21 breakup email. (3) Objection — acknowledge + reframe templates for: too expensive, not right time, have a competitor, send more info. (4) Post-Demo closing — day 0 reflection email, day 3 check-in, day 7 social proof, day 14 decision nudge. Generate the full sequence for the scenario described.`,
  },
];

export function getSkillByName(name: string): Skill | undefined {
  return SKILLS.find((s) => s.name === name);
}

export function getAllSkillDescriptions(): string {
  return SKILLS.map((s) => `- **${s.name}**: ${s.description}`).join("\n");
}

