"use client";

interface SkillTagProps {
  skill: string;
}

const SKILL_LABELS: Record<string, string> = {
  "founder-context": "Founder Context",
  "idea-validation": "Idea Validation",
  "competitor-research": "Competitor Research",
  "customer-segments": "Customer Segments",
  "landing-page": "Landing Page",
  "prototype-sprint": "Prototype Sprint",
  "mvp-scope": "MVP Scope",
  "pitch-deck": "Pitch Deck",
  "first-users": "First Users",
  "launch-plan": "Launch Plan",
  "social-content": "Social Content",
  "mom-test": "Mom Test",
  "gtm-strategy": "GTM Strategy",
  "sales-outreach": "Sales Outreach",
  "follow-up-tracks": "Follow-Up Tracks",
};

export function SkillTag({ skill }: SkillTagProps) {
  const label = SKILL_LABELS[skill] ?? skill;

  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: "4px",
        fontSize: "10px",
        fontWeight: 500,
        letterSpacing: "0.06em",
        textTransform: "uppercase",
        color: "#3a6e00",
        background: "rgba(58, 110, 0, 0.08)",
        border: "1px solid rgba(58, 110, 0, 0.2)",
        borderRadius: "4px",
        padding: "2px 8px",
        marginBottom: "10px",
      }}
    >
      <svg
        width="8"
        height="8"
        viewBox="0 0 8 8"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
      >
        <circle cx="4" cy="4" r="3" fill="#3a6e00" opacity="0.6" />
      </svg>
      {label}
    </span>
  );
}

