"use client";

import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { SkillTag } from "./SkillTag";

interface MessageProps {
  role: "user" | "assistant";
  content: string;
  isStreaming?: boolean;
}

function parseSkillTag(content: string): { skill: string | null; body: string } {
  const match = content.match(/^\[skill:\s*([a-z-]+)\]\n?([\s\S]*)/);
  if (match) {
    return { skill: match[1], body: match[2].trimStart() };
  }
  return { skill: null, body: content };
}

export function Message({ role, content, isStreaming }: MessageProps) {
  if (role === "user") {
    return (
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          marginBottom: "16px",
        }}
      >
        <div
          style={{
            maxWidth: "70%",
            background: "#fff",
            border: "1px solid #d8d3c8",
            borderRadius: "12px 12px 2px 12px",
            padding: "12px 16px",
            fontSize: "14px",
            lineHeight: "1.5",
            color: "#1a1a16",
          }}
        >
          {content}
        </div>
      </div>
    );
  }

  const { skill, body } = parseSkillTag(content);

  return (
    <div
      style={{
        display: "flex",
        justifyContent: "flex-start",
        marginBottom: "20px",
      }}
    >
      <div style={{ maxWidth: "80%" }}>
        {skill && <SkillTag skill={skill} />}
        <div
          style={{
            background: "#ede9df",
            border: "1px solid #d8d3c8",
            borderRadius: "2px 12px 12px 12px",
            padding: "14px 18px",
            fontSize: "14px",
            lineHeight: "1.6",
            color: "#1a1a16",
          }}
        >
          <ReactMarkdown
            remarkPlugins={[remarkGfm]}
            components={{
              p: ({ children }) => (
                <p style={{ margin: "0 0 10px 0" }}>{children}</p>
              ),
              ul: ({ children }) => (
                <ul
                  style={{
                    margin: "6px 0 10px 0",
                    paddingLeft: "20px",
                  }}
                >
                  {children}
                </ul>
              ),
              ol: ({ children }) => (
                <ol
                  style={{
                    margin: "6px 0 10px 0",
                    paddingLeft: "20px",
                  }}
                >
                  {children}
                </ol>
              ),
              li: ({ children }) => (
                <li style={{ marginBottom: "4px" }}>{children}</li>
              ),
              h2: ({ children }) => (
                <h2
                  style={{
                    fontSize: "13px",
                    fontWeight: 600,
                    letterSpacing: "0.04em",
                    textTransform: "uppercase",
                    margin: "16px 0 8px 0",
                    color: "#3a6e00",
                  }}
                >
                  {children}
                </h2>
              ),
              h3: ({ children }) => (
                <h3
                  style={{
                    fontSize: "13px",
                    fontWeight: 600,
                    margin: "12px 0 6px 0",
                  }}
                >
                  {children}
                </h3>
              ),
              code: ({ children, className }) => {
                const isBlock = className?.startsWith("language-");
                if (isBlock) {
                  return (
                    <pre
                      style={{
                        background: "#f5f2eb",
                        border: "1px solid #d8d3c8",
                        borderRadius: "6px",
                        padding: "12px",
                        overflowX: "auto",
                        fontSize: "12px",
                        fontFamily: "monospace",
                        margin: "10px 0",
                        lineHeight: "1.5",
                        whiteSpace: "pre",
                      }}
                    >
                      <code>{children}</code>
                    </pre>
                  );
                }
                return (
                  <code
                    style={{
                      background: "#f5f2eb",
                      border: "1px solid #d8d3c8",
                      borderRadius: "3px",
                      padding: "1px 5px",
                      fontSize: "12px",
                      fontFamily: "monospace",
                    }}
                  >
                    {children}
                  </code>
                );
              },
              pre: ({ children }) => <>{children}</>,
              strong: ({ children }) => (
                <strong style={{ fontWeight: 600 }}>{children}</strong>
              ),
