"use client";

import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { SkillTag } from "./SkillTag";

interface MessageProps {
  role: "user" | "assistant";
  content: string;
  isStreaming?: boolean;
}

function parseSkillTag(content: string): { skill: string | null; body: string } {
  const match = content.match(/^\[skill:\s*([a-z-]+)\]\n?([\s\S]*)/);
  if (match) {
    return { skill: match[1], body: match[2].trimStart() };
  }
  return { skill: null, body: content };
}

export function Message({ role, content, isStreaming }: MessageProps) {
  if (role === "user") {
    return (
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
