import { Chat } from "@/components/Chat";
import { SKILLS } from "@/lib/skills";

export default function Home() {
  const phaseOneSkills = [
    "founder-context",
    "idea-validation",
    "competitor-research",
    "customer-segments",
  ];
  const phaseTwoSkills = ["landing-page", "prototype-sprint", "mvp-scope"];
  const phaseThreeSkills = ["pitch-deck"];
  const phaseFourSkills = ["first-users", "launch-plan", "social-content"];
  const phaseFiveSkills = [
    "mom-test",
    "gtm-strategy",
    "sales-outreach",
    "follow-up-tracks",
  ];

  return (
    <div
      style={{
        display: "flex",
        height: "100dvh",
        overflow: "hidden",
      }}
    >
      {/* Sidebar */}
      <aside
        style={{
          width: "220px",
          flexShrink: 0,
          borderRight: "1px solid #d8d3c8",
          display: "flex",
          flexDirection: "column",
          overflowY: "auto",
          background: "#ede9df",
        }}
        className="sidebar"
      >
        {/* Brand */}
        <div
          style={{
            padding: "20px 16px 16px",
            borderBottom: "1px solid #d8d3c8",
          }}
        >
          <a
            href="https://joinhabitat.eu"
            target="_blank"
            rel="noopener noreferrer"
            style={{
              fontSize: "11px",
              fontWeight: 500,
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              color: "#3a6e00",
              textDecoration: "none",
            }}
          >
            Habitat
          </a>
          <p
            style={{
              fontSize: "11px",
              color: "#8a8578",
              marginTop: "2px",
            }}
          >
            Cofounder AI
          </p>
        </div>

        {/* Skills nav */}
        <nav style={{ padding: "12px 8px", flex: 1 }}>
          {[
            { label: "Ideation", skills: phaseOneSkills },
            { label: "Building", skills: phaseTwoSkills },
            { label: "Pitch", skills: phaseThreeSkills },
            { label: "Launch", skills: phaseFourSkills },
            { label: "Sales & GTM", skills: phaseFiveSkills },
          ].map(({ label, skills: skillNames }) => (
            <div key={label} style={{ marginBottom: "16px" }}>
              <p
                style={{
                  fontSize: "9px",
                  fontWeight: 500,
                  letterSpacing: "0.1em",
                  textTransform: "uppercase",
                  color: "#8a8578",
                  padding: "0 8px",
                  marginBottom: "4px",
                }}
              >
                {label}
              </p>
              {skillNames.map((name) => {
                const skill = SKILLS.find((s) => s.name === name);
                if (!skill) return null;
                return (
                  <div
                    key={name}
                    style={{
                      padding: "5px 8px",
                      borderRadius: "6px",
                      fontSize: "12px",
                      color: "#1a1a16",
                      cursor: "default",
                      lineHeight: "1.3",
                    }}
                  >
                    {name
                      .split("-")
                      .map((w) => w[0].toUpperCase() + w.slice(1))
                      .join(" ")}
                  </div>
                );
              })}
            </div>
          ))}
        </nav>

        <div
          style={{
            padding: "12px 16px",
            borderTop: "1px solid #d8d3c8",
            fontSize: "11px",
            color: "#8a8578",
          }}
        >
          {SKILLS.length} skills loaded
        </div>
      </aside>

      {/* Main chat */}
      <main
        style={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
          minWidth: 0,
        }}
      >
        <Chat />
      </main>

      <style>{`
        @media (max-width: 600px) {
          .sidebar { display: none; }
        }
      `}</style>
    </div>
  );
}

