  },
  {
    label: "Sales & GTM",
    skills: ["mom-test", "gtm-strategy", "sales-outreach", "follow-up-tracks"],
  },
];

export function AppLayout() {
  const [triggerMessage, setTriggerMessage] = useState<string | null>(null);
  const [activeSkill, setActiveSkill] = useState<string | null>(null);

  function handleSkillClick(name: string) {
    const prompt = SKILL_PROMPTS[name] ?? `Help me with ${name}`;
    setActiveSkill(name);
    setTriggerMessage(prompt);
  }

  return (
    <div style={{ display: "flex", height: "100dvh", overflow: "hidden" }}>
      {/* Sidebar */}
      <aside
        className="sidebar"
        style={{
          width: "220px",
          flexShrink: 0,
          borderRight: "1px solid #d8d3c8",
          display: "flex",
          flexDirection: "column",
          overflowY: "auto",
          background: "#ede9df",
        }}
      >
        {/* Brand */}
        <div style={{ padding: "20px 16px 16px", borderBottom: "1px solid #d8d3c8" }}>
          <a
            href="https://joinhabitat.eu"
            target="_blank"
            rel="noopener noreferrer"
            style={{
              fontSize: "11px",
              fontWeight: 500,
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              color: "#3a6e00",
              textDecoration: "none",
            }}
          >
            Habitat
          </a>
          <p style={{ fontSize: "11px", color: "#8a8578", marginTop: "2px" }}>
            Cofounder AI
          </p>
        </div>

        {/* Skills nav */}
        <nav style={{ padding: "12px 8px", flex: 1 }}>
          {PHASES.map(({ label, skills: skillNames }) => (
            <div key={label} style={{ marginBottom: "16px" }}>
              <p
                style={{
                  fontSize: "9px",
                  fontWeight: 500,
                  letterSpacing: "0.1em",
                  textTransform: "uppercase",
                  color: "#8a8578",
                  padding: "0 8px",
                  marginBottom: "4px",
                }}
              >
                {label}
              </p>
              {skillNames.map((name) => {
                const isActive = activeSkill === name;
                return (
                  <button
                    key={name}
                    onClick={() => handleSkillClick(name)}
                    style={{
                      display: "block",
                      width: "100%",
                      textAlign: "left",
                      padding: "6px 8px",
                      borderRadius: "6px",
                      fontSize: "12px",
                      color: isActive ? "#3a6e00" : "#1a1a16",
                      background: isActive ? "rgba(58,110,0,0.08)" : "transparent",
                      border: "none",
                      cursor: "pointer",
                      fontFamily: "inherit",
                      lineHeight: "1.3",
                      transition: "background 0.1s, color 0.1s",
                    }}
                    onMouseEnter={(e) => {
                      if (!isActive) {
                        (e.currentTarget as HTMLButtonElement).style.background = "rgba(0,0,0,0.04)";
                      }
                    }}
                    onMouseLeave={(e) => {
                      if (!isActive) {
                        (e.currentTarget as HTMLButtonElement).style.background = "transparent";
                      }
                    }}
                  >
                    {name.split("-").map((w) => w[0].toUpperCase() + w.slice(1)).join(" ")}
                  </button>
                );
              })}
            </div>
          ))}
        </nav>

        <div
          style={{
            padding: "12px 16px",
            borderTop: "1px solid #d8d3c8",
            fontSize: "11px",
            color: "#8a8578",
          }}
        >
          {SKILLS.length} skills loaded
        </div>
      </aside>

      {/* Main chat */}
      <main
        style={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
          minWidth: 0,
        }}
      >
        <Chat
          triggerMessage={triggerMessage}
          onTriggerConsumed={() => setTriggerMessage(null)}
        />
      </main>

      <style>{`
        @media (max-width: 600px) {
          .sidebar { display: none; }
        }
      `}</style>
    </div>
  );
}

