                input.trim() && !isLoading ? "#3a6e00" : "#d8d3c8",
              cursor: input.trim() && !isLoading ? "pointer" : "default",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              flexShrink: 0,
              transition: "background 0.15s",
            }}
          >
            <svg
              width="14"
              height="14"
              viewBox="0 0 14 14"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                d="M7 12V2M7 2L3 6M7 2L11 6"
                stroke="white"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </button>
        </div>
        <p
          style={{
            textAlign: "center",
            fontSize: "11px",
            color: "#8a8578",
            marginTop: "8px",
          }}
        >
          ⌘↩ to send
        </p>
      </div>
    </div>
  );
}

